import{_ as t,c as a,o as l,ag as o}from"./chunks/framework.DD2hp6gW.js";const g=JSON.parse('{"title":"Order Management","description":"","frontmatter":{},"headers":[],"relativePath":"order-management.md","filePath":"order-management.md","lastUpdated":1777110900000}'),r={name:"order-management.md"};function i(n,e,s,d,c,h){return l(),a("div",null,e[0]||(e[0]=[o('<h1 id="order-management" tabindex="-1">Order Management <a class="header-anchor" href="#order-management" aria-label="Permalink to &quot;Order Management&quot;">​</a></h1><p>For store administrators, OptionBay makes it easy to view and process custom product selections directly within the WordPress dashboard. All customer choices are permanently stored and accessible for fulfillment.</p><h2 id="viewing-customer-selections" tabindex="-1">Viewing Customer Selections <a class="header-anchor" href="#viewing-customer-selections" aria-label="Permalink to &quot;Viewing Customer Selections&quot;">​</a></h2><p>To view the options selected for an order:</p><ol><li>Navigate to <strong>WooCommerce &gt; Orders</strong>.</li><li>Click on the order you wish to view.</li><li>In the <strong>Item List</strong>, you will see the selected options listed under each product line item.</li></ol><h3 id="how-it-looks" tabindex="-1">How It Looks <a class="header-anchor" href="#how-it-looks" aria-label="Permalink to &quot;How It Looks&quot;">​</a></h3><p>Each addon selection appears as a key-value pair below the product name:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Key</th><th style="text-align:left;">Value</th></tr></thead><tbody><tr><td style="text-align:left;">Engraving Text</td><td style="text-align:left;">Hello World</td></tr><tr><td style="text-align:left;">Size</td><td style="text-align:left;">Large (+$5.00)</td></tr><tr><td style="text-align:left;">Gift Wrapping</td><td style="text-align:left;">Yes (+$10.00)</td></tr><tr><td style="text-align:left;">Color</td><td style="text-align:left;">Midnight Blue</td></tr><tr><td style="text-align:left;">Logo</td><td style="text-align:left;"><a href="#">my-logo.png</a> (clickable link)</td></tr></tbody></table><h3 id="data-storage" tabindex="-1">Data Storage <a class="header-anchor" href="#data-storage" aria-label="Permalink to &quot;Data Storage&quot;">​</a></h3><p>OptionBay saves selections as <strong>Order Item Meta</strong>. This means:</p><ul><li>The data is permanently attached to the specific order item.</li><li>It will remain available even if you delete the original Option Group or the Product.</li><li>Each selection is stored as a separate meta entry with the field&#39;s <strong>Label</strong> as the meta key and the customer&#39;s <strong>selection</strong> as the meta value.</li></ul><h2 id="handling-file-uploads" tabindex="-1">Handling File Uploads <a class="header-anchor" href="#handling-file-uploads" aria-label="Permalink to &quot;Handling File Uploads&quot;">​</a></h2><p>If your customer uploaded a file (e.g., a logo for a custom print):</p><ul><li>The file name will be shown in the order details.</li><li>The name will be a <strong>clickable link</strong> that opens the file in a new browser tab.</li><li>Files are stored in your WordPress <strong>Media Library</strong> under the standard upload directory, making them easy to manage, download, and access for fulfillment.</li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>You can access uploaded files directly from the WordPress Media Library if you need to download them in bulk for fulfillment. Search for the filename shown in the order.</p></div><h2 id="fulfillment-workflow" tabindex="-1">Fulfillment Workflow <a class="header-anchor" href="#fulfillment-workflow" aria-label="Permalink to &quot;Fulfillment Workflow&quot;">​</a></h2><p>The custom selection data is available to other plugins and integrations that read WooCommerce order item meta:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Integration</th><th style="text-align:left;">Compatibility</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>PDF Invoice Plugins</strong></td><td style="text-align:left;">Most WooCommerce PDF Invoicing plugins (like WooCommerce PDF Invoices &amp; Packing Slips) will automatically include the OptionBay meta data on the generated invoice.</td></tr><tr><td style="text-align:left;"><strong>Shipping Platforms</strong></td><td style="text-align:left;">Platforms like ShipStation that pull order item data will generally see these selections as line item properties.</td></tr><tr><td style="text-align:left;"><strong>REST API</strong></td><td style="text-align:left;">The selections are accessible through the WooCommerce REST API as standard order item meta, making custom integrations straightforward.</td></tr></tbody></table><h2 id="price-integrity" tabindex="-1">Price Integrity <a class="header-anchor" href="#price-integrity" aria-label="Permalink to &quot;Price Integrity&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>The prices saved in the order are <strong>&quot;frozen&quot;</strong> at the time of purchase. If you change the price of an addon later, it will <strong>not</strong> affect orders that have already been placed. This ensures accurate historical records and prevents retroactive price changes from affecting completed transactions.</p></div><h2 id="manual-order-creation" tabindex="-1">Manual Order Creation <a class="header-anchor" href="#manual-order-creation" aria-label="Permalink to &quot;Manual Order Creation&quot;">​</a></h2><p>When creating an order manually from the backend:</p><ol><li>Add the product to the order.</li><li>You can manually add meta keys and values to the line item to match the customer&#39;s needs if they communicated their choices outside of the website (e.g., via email or phone).</li><li>Note: The interactive Addon Builder interface is not currently available for manual backend orders — it is designed for customer-facing frontend use only.</li></ol><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./cart-checkout.html">Cart &amp; Checkout Integration</a></li><li><a href="./settings.html">Global Settings</a></li></ul>',25)]))}const u=t(r,[["render",i]]);export{g as __pageData,u as default};
